            $parent = Category::create([
                'name' => $catData['name'],
                'user_id' => null,
            ]);

            foreach ($catData['sub_categories'] as $subData) {
                $child = Category::create([
                    'name' => $subData['name'],
                    'parent_id' => $parent->id,
                    'user_id' => null,
                ]);

                if (! empty($subData['icon'])) {
                    $child->clearMediaCollection(Category::CATEGORY_IMAGE);
                    $child->addMediaFromString($subData['icon'])
                        ->usingFileName('icon.svg')
                        ->toMediaCollection(Category::CATEGORY_IMAGE);
                }
            }
        }
